<?php require_once __DIR__.'/../inc/bootstrap.php'; $files=scan_scripts(); ?>
<div class="stack"><div class="notice">Inventaire des fichiers scripts visibles par l’UI.</div><div class="card"><table><thead><tr><th>chemin relatif</th><th>taille</th><th>modifié</th><th>exécutable</th></tr></thead><tbody><?php foreach($files as $f): $abs=script_abs($f); ?><tr><td><code><?= h($f) ?></code></td><td><?= h((string)filesize($abs)) ?> o</td><td><?= h(date('Y-m-d H:i:s', filemtime($abs))) ?></td><td><span class="status <?= is_executable($abs)?'up':'warn' ?>"><?= is_executable($abs)?'YES':'NO' ?></span></td></tr><?php endforeach; ?></tbody></table></div></div>
